322вҶ’+    private TeamRoleMaps getTeamRoleMaps(String spaceId, Long spaceNodeId) {
323вҶ’+        String controlId;
324вҶ’+        if (controlService.existsByControlId(spaceNodeId.toString())) {
325вҶ’+            controlId = spaceNodeId.toString();
326вҶ’+        } else {
327вҶ’+            Long extendNodeId = getNodeExtendNodeId(spaceNodeId);
