334вҶ’+
335вҶ’+        List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
336вҶ’+        if (CollectionUtils.isEmpty(controlRoles)) {
337вҶ’+            return TeamRoleMaps.empty();
