364вҶ’+    private List<TeamRoleTreeVo> convertToTeamRoleTree(List<TeamMemberVo> teamTree, TeamRoleMaps roleMaps) {
365вҶ’+        List<TeamRoleTreeVo> result = new ArrayList<>();
366вҶ’+        for (TeamMemberVo team : teamTree) {
367вҶ’+            TeamRoleTreeVo vo = new TeamRoleTreeVo();
368вҶ’+            vo.setTeamId(team.getTeamId());
369вҶ’+            vo.setUnitId(roleMaps.teamIdToUnitId().get(team.getTeamId()));
370вҶ’+            vo.setTeamName(team.getTeamName());
371вҶ’+            vo.setParentId(team.getParentTeamId());
372вҶ’+            vo.setMemberCount(team.getMemberCount());
373вҶ’+            vo.setRole(roleMaps.teamIdToRole().get(team.getTeamId()));
374вҶ’+            if (CollectionUtils.isNotEmpty(team.getChildrenList())) {
375вҶ’+                vo.setChildren(convertToTeamRoleTree(team.getChildrenList(), roleMaps));
376вҶ’+            } else {
377вҶ’+                vo.setChildren(List.of());
378вҶ’+            }
379вҶ’+            result.add(vo);
380вҶ’+        }
381вҶ’+        return result;
382вҶ’+    }
