387вҶ’+        for (TeamRoleTreeVo node : tree) {
388вҶ’+            result.add(node);
389вҶ’+            if (CollectionUtils.isNotEmpty(node.getChildren())) {
390вҶ’+                result.addAll(flattenTree(node.getChildren()));
391вҶ’+            }
392вҶ’+        }
393вҶ’+        return result;
394вҶ’+    }
