397вҶ’+    private List<TeamRoleTreeVo> flattenAndFilter(List<TeamRoleTreeVo> tree, String keyword) {
398вҶ’+        List<TeamRoleTreeVo> result = new ArrayList<>();
399вҶ’+        String lowerKeyword = keyword.toLowerCase();
400вҶ’+        for (TeamRoleTreeVo node : tree) {
401вҶ’+            if (node.getTeamName() != null && node.getTeamName().toLowerCase().contains(lowerKeyword)) {
402вҶ’+                result.add(node);
403вҶ’+            }
404вҶ’+            if (CollectionUtils.isNotEmpty(node.getChildren())) {
405вҶ’+                result.addAll(flattenAndFilter(node.getChildren(), keyword));
406вҶ’+            }
407вҶ’+        }
408вҶ’+        return result;
409вҶ’+    }
