 600вҶ’+    private EditRoleResultVo checkMemberTeamConflict(String spaceId, Long spaceNodeId, String newRole, List<Long> unitIds) {
 601вҶ’+        List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);
 602вҶ’+        List<NodeRoleUnit> memberUnits = unitInfos.stream()
 603вҶ’+                .filter(u -> u.getUnitType() != null && u.getUnitType() == 3)
 604вҶ’+                .toList();
 605вҶ’+
 606вҶ’+        if (memberUnits.isEmpty()) {
 607вҶ’+            return EditRoleResultVo.noConflict();
 608вҶ’+        }
 609вҶ’+
 610вҶ’+        NodeRoleLevel newLevel = NodeRoleLevel.fromRoleTag(newRole);
 611вҶ’+
 612вҶ’+        // жү№йҮҸж”¶йӣҶжүҖжңүжҲҗе‘ҳе…іиҒ”зҡ„ unitIdпјҢеҮҸе°‘ gRPC и°ғз”Ёж¬Ўж•°
 613вҶ’+        Set<Long> allMemberUnitIds = new HashSet<>();
 614вҶ’+        for (NodeRoleUnit memberUnit : memberUnits) {
 615вҶ’+            List<Long> memberAllUnitIds = apitableGrpcClientService.getUnitsByMember(memberUnit.getUnitRefId(), spaceId);
 616вҶ’+            if (CollectionUtils.isNotEmpty(memberAllUnitIds)) {
 617вҶ’+                allMemberUnitIds.addAll(memberAllUnitIds);
 618вҶ’+            }
 619вҶ’+        }
 620вҶ’+        // жҺ’йҷӨжң¬ж¬Ўж“ҚдҪңзҡ„ unitId
 621вҶ’+        allMemberUnitIds.removeAll(unitIds);
 622вҶ’+        if (allMemberUnitIds.isEmpty()) {
 623вҶ’+            return EditRoleResultVo.noConflict();
 624вҶ’+        }
 625вҶ’+
 626вҶ’+        // дёҖж¬ЎжҖ§жҹҘиҜўжүҖжңүе…іиҒ” unit еңЁиҜҘиҠӮзӮ№дёҠзҡ„жқғйҷҗ
 627вҶ’+        List<ControlRoleEntity> teamRoles = controlRoleService.getByControlIdAndUnitIds(
 628вҶ’+                spaceNodeId.toString(), new ArrayList<>(allMemberUnitIds));
 629вҶ’+
 630вҶ’+        // жүҫеҮәжқғйҷҗй«ҳдәҺжң¬ж¬Ўи®ҫзҪ®зҡ„е°Ҹз»„
 631вҶ’+        for (ControlRoleEntity teamRole : teamRoles) {
 632вҶ’+            NodeRoleLevel teamLevel = NodeRoleLevel.fromRoleTag(teamRole.getRoleCode());
 633вҶ’+            if (teamLevel.getLevel() > newLevel.getLevel()) {
 634вҶ’+                // дёҖж¬ЎжҖ§жҹҘиҜўеҶІзӘҒе°Ҹз»„дҝЎжҒҜ
 635вҶ’+                List<NodeRoleUnit> teamInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, List.of(teamRole.getUnitId()));
 636вҶ’+                String teamName = CollectionUtils.isNotEmpty(teamInfos) ? teamInfos.getFirst().getUnitName() : "жңӘзҹҘе°Ҹз»„";
 637вҶ’+                String teamRoleDisplay = ROLE_DISPLAY_MAP.getOrDefault(teamRole.getRoleCode(), teamRole.getRoleCode());
 638вҶ’+
 639вҶ’+                return EditRoleResultVo.builder()
 640вҶ’+                        .hasConflict(true)
 641вҶ’+                        .conflictTeamName(teamName)
 642вҶ’+                        .conflictTeamRole(teamRole.getRoleCode())
 643вҶ’+                        .conflictMessage("еӣ дёәз”ЁжҲ·жүҖеӨ„зҡ„з»„еҜ№ж–ҮжЎЈжңү" + teamRoleDisplay + "жқғйҷҗпјҢжүҖд»Ҙжң¬ж¬Ўж“ҚдҪңеҗҺз”ЁжҲ·дҫқж—§еҜ№ж–ҮжЎЈжңү"
 644вҶ’+                                + teamRoleDisplay + "жқғйҷҗпјҢеҰӮжһңжғіиҰҒеҪ»еә•ж”№еҸҳз”ЁжҲ·жқғйҷҗпјҢиҜ·е°Ҷз”ЁжҲ·з§»еҮәжүҖеңЁз»„пјҢжҲ–ж”№еҸҳе…¶жүҖеңЁз»„жқғйҷҗ")
 645вҶ’+                        .build();
 646вҶ’+            }
 647вҶ’+        }
 648вҶ’+        return EditRoleResultVo.noConflict();
 649вҶ’+    }
