 790вҶ’+            // е°Ҷдёӯж–Үе…ій”®иҜҚеҸҚеҗ‘жҳ е°„дёәи§’иүІз ҒпјҢж”ҜжҢҒз”ЁжҲ·з”Ёдёӯж–Үжҗңзҙўи§’иүІ
 791вҶ’+            List<String> matchedRoleCodes = new ArrayList<>();
 792вҶ’+            for (Map.Entry<String, String> entry : ROLE_DISPLAY_MAP.entrySet()) {
 793вҶ’+                if (entry.getValue().contains(keyword)) {
 794вҶ’+                    matchedRoleCodes.add(entry.getKey());
 795вҶ’+                }
 796вҶ’+            }
 797вҶ’+            if (keyword.contains("з§»йҷӨ") || "з§»йҷӨжүҖжңүжқғйҷҗ".contains(keyword)) {
 798вҶ’+                // action=remove иЎЁзӨәз§»йҷӨжқғйҷҗпјҢold_role/new_role йҮҢдёҚдјҡеӯҳдёӯж–Ү
 799вҶ’+                // йҖҡиҝҮ action еӯ—ж®өеҢ№й…Қ
 800вҶ’+                matchedRoleCodes.add("__REMOVE__");
 801вҶ’+            }
 802вҶ’+
 803вҶ’+            wrapper.and(w -> {
 804вҶ’+                w.like(NodePermissionLogEntity::getOperatorName, keyword)
 805вҶ’+                        .or().like(NodePermissionLogEntity::getTargetName, keyword)
 806вҶ’+                        .or().like(NodePermissionLogEntity::getNewRole, keyword)
 807вҶ’+                        .or().like(NodePermissionLogEntity::getOldRole, keyword);
 808вҶ’+                for (String roleCode : matchedRoleCodes) {
 809вҶ’+                    if ("__REMOVE__".equals(roleCode)) {
 810вҶ’+                        w.or().eq(NodePermissionLogEntity::getAction, "remove");
 811вҶ’+                    } else {
 812вҶ’+                        w.or().eq(NodePermissionLogEntity::getNewRole, roleCode)
 813вҶ’+                                .or().eq(NodePermissionLogEntity::getOldRole, roleCode);
 814вҶ’+                    }
 815вҶ’+                }
 816вҶ’+            });
 817вҶ’+        }
 818вҶ’+        wrapper.orderByDesc(NodePermissionLogEntity::getCreatedAt);
 819вҶ’+
 820вҶ’+        IPage<NodePermissionLogEntity> page = page(new Page<>(pageNo, pageSize), wrapper);
 821вҶ’+        IPage<NodePermissionLogVo> voPage = page.convert(this::toVo);
 822вҶ’+        return PageHelper.build(voPage);
 823вҶ’+    }
 824вҶ’+
 825вҶ’+    @Override
 826вҶ’+    public void log(Long spaceNodeId, String spaceId, Long operatorId, String operatorName,
 827вҶ’+                    String targetName, Integer targetType, String action, String oldRole, String newRole) {
 828вҶ’+        NodePermissionLogEntity entity = NodePermissionLogEntity.builder()
 829вҶ’+                .spaceNodeId(spaceNodeId)
 830вҶ’+                .spaceId(spaceId)
 831вҶ’+                .operatorId(operatorId)
 832вҶ’+                .operatorName(operatorName)
 833вҶ’+                .targetName(targetName)
 834вҶ’+                .targetType(targetType)
 835вҶ’+                .action(action)
 836вҶ’+                .oldRole(oldRole)
 837вҶ’+                .newRole(newRole)
 838вҶ’+                .build();
 839вҶ’+        save(entity);
 840вҶ’+    }
 841вҶ’+
 842вҶ’+    private NodePermissionLogVo toVo(NodePermissionLogEntity entity) {
 843вҶ’+        NodePermissionLogVo vo = new NodePermissionLogVo();
 844вҶ’+        vo.setOperatorName(entity.getOperatorName());
 845вҶ’+        vo.setCreatedAt(entity.getCreatedAt());
 846вҶ’+        vo.setTargetName(entity.getTargetName());
 847вҶ’+
 848вҶ’+        String action = entity.getAction();
 849вҶ’+        if ("remove".equals(action)) {
 850вҶ’+            vo.setDescription("е°Ҷ " + entity.getTargetName() + " жқғйҷҗж”№дёә з§»йҷӨжүҖжңүжқғйҷҗ");
 851вҶ’+            vo.setNewRoleDisplay("з§»йҷӨжүҖжңүжқғйҷҗ");
 852вҶ’+        } else {
 853вҶ’+            String roleDisplay = ROLE_DISPLAY_MAP.getOrDefault(entity.getNewRole(), entity.getNewRole());
 854вҶ’+            vo.setDescription("е°Ҷ " + entity.getTargetName() + " жқғйҷҗж”№дёә " + roleDisplay);
 855вҶ’+            vo.setNewRoleDisplay(roleDisplay);
 856вҶ’+        }
 857вҶ’+        return vo;
 858вҶ’+    }
 859вҶ’+}
