 21вҶ’
 22вҶ’@Service
 23вҶ’public class NodePermissionLogServiceImpl
 24вҶ’        extends ServiceImpl<NodePermissionLogMapper, NodePermissionLogEntity>
 25вҶ’        implements INodePermissionLogService {
 26вҶ’
 27вҶ’    @Override
 28вҶ’    public PageInfo<NodePermissionLogVo> pageBySpaceNodeId(Long spaceNodeId, String keyword, int pageNo, int pageSize) {
 29вҶ’        LambdaQueryWrapper<NodePermissionLogEntity> wrapper = new LambdaQueryWrapper<>();
 30вҶ’        wrapper.eq(NodePermissionLogEntity::getSpaceNodeId, spaceNodeId);
 31вҶ’        if (StrUtil.isNotBlank(keyword)) {
 32вҶ’            // е°Ҷдёӯж–Үе…ій”®иҜҚеҸҚеҗ‘жҳ е°„дёәи§’иүІз ҒпјҢж”ҜжҢҒз”ЁжҲ·з”Ёдёӯж–Үжҗңзҙўи§’иүІ
 33вҶ’            List<String> matchedRoleCodes = new ArrayList<>();
 34вҶ’            for (Map.Entry<String, String> entry : ROLE_DISPLAY_MAP.entrySet()) {
 35вҶ’                if (entry.getValue().contains(keyword)) {
 36вҶ’                    matchedRoleCodes.add(entry.getKey());
 37вҶ’                }
 38вҶ’            }
 39вҶ’            if (keyword.contains("з§»йҷӨ") || "з§»йҷӨжүҖжңүжқғйҷҗ".contains(keyword)) {
 40вҶ’                // action=remove иЎЁзӨәз§»йҷӨжқғйҷҗпјҢold_role/new_role йҮҢдёҚдјҡеӯҳдёӯж–Ү
 41вҶ’                // йҖҡиҝҮ action еӯ—ж®өеҢ№й…Қ
 42вҶ’                matchedRoleCodes.add("__REMOVE__");
 43вҶ’            }
 44вҶ’
 45вҶ’            wrapper.and(w -> {
 46вҶ’                w.like(NodePermissionLogEntity::getOperatorName, keyword)
 47вҶ’                        .or().like(NodePermissionLogEntity::getTargetName, keyword)
 48вҶ’                        .or().like(NodePermissionLogEntity::getNewRole, keyword)
 49вҶ’                        .or().like(NodePermissionLogEntity::getOldRole, keyword);
 50вҶ’                for (String roleCode : matchedRoleCodes) {
 51вҶ’                    if ("__REMOVE__".equals(roleCode)) {
 52вҶ’                        w.or().eq(NodePermissionLogEntity::getAction, "remove");
 53вҶ’                    } else {
 54вҶ’                        w.or().eq(NodePermissionLogEntity::getNewRole, roleCode)
 55вҶ’                                .or().eq(NodePermissionLogEntity::getOldRole, roleCode);
 56вҶ’                    }
 57вҶ’                }
 58вҶ’            });
 59вҶ’        }
 60вҶ’        wrapper.orderByDesc(NodePermissionLogEntity::getCreatedAt);
 61вҶ’
 62вҶ’        IPage<NodePermissionLogEntity> page = page(new Page<>(pageNo, pageSize), wrapper);
 63вҶ’        IPage<NodePermissionLogVo> voPage = page.convert(this::toVo);
 64вҶ’        return PageHelper.build(voPage);
 65вҶ’    }
 66вҶ’
 67вҶ’    @Override
 68вҶ’    public void log(Long spaceNodeId, String spaceId, Long operatorId, String operatorName,
 69вҶ’                    String targetName, Integer targetType, String action, String oldRole, String newRole) {
 70вҶ’        NodePermissionLogEntity entity = NodePermissionLogEntity.builder()
 71вҶ’                .spaceNodeId(spaceNodeId)
 72вҶ’                .spaceId(spaceId)
 73вҶ’                .operatorId(operatorId)
 74вҶ’                .operatorName(operatorName)
 75вҶ’                .targetName(targetName)
