 84вҶ’    private NodePermissionLogVo toVo(NodePermissionLogEntity entity) {
 85вҶ’        NodePermissionLogVo vo = new NodePermissionLogVo();
 86вҶ’        vo.setOperatorName(entity.getOperatorName());
 87вҶ’        vo.setCreatedAt(entity.getCreatedAt());
 88вҶ’        vo.setTargetName(entity.getTargetName());
 89вҶ’
 90вҶ’        String action = entity.getAction();
 91вҶ’        if ("remove".equals(action)) {
 92вҶ’            vo.setDescription("е°Ҷ " + entity.getTargetName() + " жқғйҷҗж”№дёә з§»йҷӨжүҖжңүжқғйҷҗ");
 93вҶ’            vo.setNewRoleDisplay("з§»йҷӨжүҖжңүжқғйҷҗ");
